import React, { useState } from "react";
import { useSearchParams } from "react-router-dom";
import ProductList from "./products/ProductList";
import productsData from "../assets/mockdata/products.json";
import Carousel from "./ui/Carousel";
import FeaturedSections from "./layout/FeaturedSections";

const Home = () => {
  const [products] = useState(productsData);
  const [searchParams] = useSearchParams();
  const selectedCategory = searchParams.get("category") || "Todas";
  const isFiltering = selectedCategory !== "Todas";

  const filteredProducts =
    selectedCategory === "Todas"
      ? products
      : products.filter((p) => p.category === selectedCategory);

  return (
  <div>
    <div className="container">
      
      {/* SOLO mostrar esto si NO hay filtro */}
      {!isFiltering && (
        <>
          <Carousel />
          <hr className="my-5" />
          <FeaturedSections />
          <hr className="my-5" />
        </>
      )}

      <ProductList products={filteredProducts} />
    </div>
  </div>
);
};

export default Home;
